33	    /// Spawn the spinning echo worker over two fresh leaked
34	    /// rings, optionally pinning it to `worker_cpu`.
35	    pub fn new(worker_cpu: Option<usize>) -> Self {
36	        let (req_tx, mut req_rx) = leak_ring();
37	        let (mut resp_tx, resp_rx) = leak_ring();
38	        let worker = thread::spawn(move || {
39	            pin::pin_current(worker_cpu);
40	            loop {
41	                let v = {
42	                    let slot = req_rx
43	                        .reserve_slot_with::<Msg>(|_| {
44	                            core::hint::spin_loop();
45	                            true
46	                        })
47	                        .expect("spin closure never gives up");
48	                    let v = *slot;
49	                    slot.release();
50	                    v
51	                };
52	                if v == STOP {
53	                    break;
54	                }
55	                let mut slot = resp_tx
56	                    .reserve_slot_with::<Msg>(|_| {
57	                        core::hint::spin_loop();
58	                        true
59	                    })
60	                    .expect("spin closure never gives up");
61	                *slot = v;
62	                slot.commit();
63	            }
64	        });
65	        Self {
66	            req_tx,
67	            resp_rx,
68	            worker: Some(worker),
69	            counter: 0,
70	        }
71	    }
72	}
