73	impl<'a> MpscProducer<'a> {
74	    /// Build the handle from [`MpscRing::split`](super::MpscRing::split)'s
75	    /// geometry snapshot.
76	    pub(super) fn new(
77	        header: &'a MpscHeader,
78	        seqs: *const AtomicU32,
79	        slots: *mut u8,
80	        slot_size: u32,
81	        mask: u32,
82	    ) -> Self {
83	        MpscProducer {
84	            header,
85	            seqs,
86	            slots,
87	            slot_size,
88	            mask,
89	        }
90	    }
91	
92	    /// The header's app-owned scratch line — same contract as
93	    /// the SPSC endpoints' `user()`.
94	    pub fn user(&self) -> &[AtomicU32; USER_WORDS] {
95	        &self.header.user
96	    }
97	
98	    /// The seq word for free-running position `idx`.
99	    fn seq(&self, idx: u32) -> &AtomicU32 {
100	        // SAFETY: idx is masked to < capacity, inside the seq
101	        // array validated at init/attach.
102	        unsafe { &*self.seqs.add((idx & self.mask) as usize) }
103	    }
104	
105	    /// Claim the next slot position, fill it in place, commit
106	    /// on closure return; retry a full ring under the injected
107	    /// wait policy → [`Full`].
108	    ///
109	    /// - `fill` writes the message through `&mut T`; commit is
110	    ///   by construction — there is no abandonment state (an
111	    ///   SPSC-style guard could be dropped, and in MPSC an
112	    ///   abandoned *claim* wedges the queue).
113	    /// - `on_full` is called after each failed attempt with
114	    ///   the attempt count (0-based, saturating); returning
115	    ///   `false` gives up → `Err(Full)`. Pass `|_| false` for
116	    ///   a single non-blocking probe. A send that returns
117	    ///   `Full` has zero protocol footprint (the overflow-FIFO
118	    ///   seam — see the design doc's "Overflow readiness").
119	    /// - Losing a claim race to another producer is *not* a
120	    ///   policy call: the system made progress; this producer
121	    ///   just retries with the fresher index.
122	    /// - If `fill` panics, the unwind publishes a tombstoned
123	    ///   commit: the consumer releases the slot without
124	    ///   delivering it, and the queue keeps flowing.
125	    pub fn send_with<T>(
126	        &self,
127	        mut on_full: impl FnMut(u32) -> bool,
128	        fill: impl FnOnce(&mut T),
129	    ) -> Result<(), Full>
130	    where
131	        T: FromBytes + IntoBytes + KnownLayout,
132	    {
133	        check_type::<T>(self.slot_size);
134	        let mut pos = self.header.producer_idx.load(Ordering::Relaxed);
135	        let mut attempt = 0u32;
136	        loop {
137	            // Acquire pairs with the consumer's Release in
138	            // release(): a claimable seq means the previous
139	            // lap's reads are done.
140	            let seq = self.seq(pos).load(Ordering::Acquire);
141	            let diff = seq.wrapping_sub(pos) as i32;
142	            if diff == 0 {
143	                // Claimable. Weak CAS: a spurious failure just
144	                // retries with the fresher index.
145	                match self.header.producer_idx.compare_exchange_weak(
146	                    pos,
147	                    pos.wrapping_add(1),
148	                    Ordering::Relaxed,
149	                    Ordering::Relaxed,
150	                ) {
151	                    Ok(_) => break,
152	                    Err(actual) => pos = actual,
153	                }
154	            } else if diff < 0 {
155	                // Slot's previous occupant not yet released.
156	                // Re-read the index first: if it moved, this
157	                // was a stale pos (e.g. a tombstoned slot we
158	                // raced), not a full ring — no policy call.
159	                let cur = self.header.producer_idx.load(Ordering::Relaxed);
160	                if cur != pos {
161	                    pos = cur;
162	                    continue;
163	                }
164	                if !on_full(attempt) {
165	                    return Err(Full);
166	                }
167	                attempt = attempt.saturating_add(1);
168	            } else {
169	                // Another producer claimed pos; ours is stale.
170	                pos = self.header.producer_idx.load(Ordering::Relaxed);
171	            }
172	        }
173	        // pos is exclusively ours until the seq commit store.
174	        let msg = slot_ptr(self.slots, pos, self.mask, self.slot_size) as *mut T;
175	        let commit = pos.wrapping_add(1);
176	        let guard = TombstoneOnUnwind {
177	            seq: self.seq(pos),
178	            commit,
179	        };
180	        // SAFETY: msg is in-bounds and aligned (check_type +
181	        // cache-line slot base), any byte pattern is a valid T
182	        // (FromBytes bound), and the claim CAS gives exclusive
183	        // slot access until the commit store below.
184	        fill(unsafe { &mut *msg });
185	        // Normal path: disarm the unwind guard, then publish.
186	        let seq = guard.seq;
187	        core::mem::forget(guard);
188	        // Release pairs with the consumer's Acquire seq load:
189	        // observing pos + 1 means the filled bytes are visible.
190	        seq.store(commit, Ordering::Release);
191	        Ok(())
192	    }
193	}
